SELECT KPLG_DATUM, KPLG_MENGE, KPLG_IDLGOR, KPLG_IDAIBK, KPLG_IDSKKP,  CASE WHEN (CASE WHEN KP_TYP_POSITION = 0 THEN CASE WHEN ISNULL(tSK_KALK_EBENE_POS.KP_EBENE_POS_TYP_LAGER_BUCHUNG, 0) = 0 THEN 0 ELSE 1 END ELSE CASE WHEN KP_TYP_POSITION = 1 THEN CASE WHEN KP_TYP_KALK_POS = 1 THEN CASE WHEN ISNULL(KP_UNTEREBENE_TYP_LAGER_BUCHUNG, 0) = 0 THEN CASE WHEN ISNULL(tSK_KALK_EBENE_POS.KP_EBENE_POS_TYP_LAGER_BUCHUNG, 0) = 0 THEN 0 ELSE 1 END ELSE 0 END ELSE 0 END ELSE 0 END END) = 1 THEN  CASE WHEN tNUKR.NK_TYP_ARTIKEL_IDENT_VALID = 0 THEN  CASE WHEN tNUKR.NK_TYP_ARTIKEL_IDENT_DARSTELLUNG = 0 THEN  0  ELSE  CASE WHEN tNUKR.NK_TYP_ARTIKEL_IDENT_DARSTELLUNG = 1 THEN  CASE WHEN tARST.AR_TYP_ARTIKEL_IDENT_DARSTELLUNG = 0 THEN  0  ELSE  CASE WHEN ABS(ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN  1  ELSE  CASE WHEN ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0) = 0 THEN  CASE WHEN KPLG_IDAIBK IS NULL THEN  3  ELSE  2  END  ELSE  2  END  END  END  ELSE  CASE WHEN ABS(ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN  1  ELSE  CASE WHEN ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0) = 0 THEN  CASE WHEN KPLG_IDAIBK IS NULL THEN  3  ELSE  2  END  ELSE  2  END  END  END  END  ELSE  CASE WHEN tNUKR.NK_TYP_ARTIKEL_IDENT_VALID = 1 THEN  CASE WHEN KP_TYP_PRUEFUNG_ARTIKEL_IDENT = 0 THEN  CASE WHEN tARST.AR_TYP_ARTIKEL_IDENT_DARSTELLUNG = 0 THEN  CASE WHEN tNUKR.NK_TYP_ARTIKEL_IDENT_DARSTELLUNG = 0 OR tNUKR.NK_TYP_ARTIKEL_IDENT_DARSTELLUNG = 1 THEN  0  ELSE  CASE WHEN ABS(ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN  1  ELSE  CASE WHEN ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0) = 0 THEN  CASE WHEN KPLG_IDAIBK IS NULL THEN  3  ELSE  2  END  ELSE  2  END  END  END  ELSE  CASE WHEN ABS(ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN  1  ELSE  CASE WHEN ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0) = 0 THEN  CASE WHEN KPLG_IDAIBK IS NULL THEN  3  ELSE  2  END  ELSE  2  END  END  END  ELSE  CASE WHEN ABS(ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN  1  ELSE  CASE WHEN ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0) = 0 THEN  CASE WHEN KPLG_IDAIBK IS NULL THEN  4  ELSE  2  END  ELSE  2  END  END  END  ELSE  CASE WHEN ABS(ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN  1  ELSE  CASE WHEN ISNULL(tARID_BEWP_MENGEN.AIBP_MENGE_GESAMT, 0) = 0 THEN  CASE WHEN KPLG_IDAIBK IS NULL THEN  4  ELSE  2  END  ELSE  2  END  END  END  END  ELSE NULL END AS KPLG_STATUS_ARST_IDENT, KPLG_IDFO, KPLG_VARIABLEN, KPLG_DIMENSIONEN, KPLG_WERTE, KPLG_FORMEL, KPLG_ANZAHL_FORMEL, tSK_KALP_LGBEWE.ID AS ID  FROM ((((((((((((((tSK_KALP_LGBEWE LEFT JOIN tLG_ORTE ON tLG_ORTE.ID = KPLG_IDLGOR)  LEFT JOIN tMARB ON tMARB.ID = KPLG_IDMR)  LEFT JOIN (SELECT SUM(AIBP_MENGE) AS AIBP_MENGE_GESAMT, AIBP_IDAIBK FROM tARID_BEWP GROUP BY AIBP_IDAIBK) AS tARID_BEWP_MENGEN ON tARID_BEWP_MENGEN.AIBP_IDAIBK = tSK_KALP_LGBEWE.KPLG_IDAIBK) LEFT JOIN tSK_KALP ON tSK_KALP.ID = tSK_KALP_LGBEWE.KPLG_IDSKKP)  LEFT JOIN tARST ON tARST.ID = tSK_KALP.KP_IDAR) LEFT JOIN (SELECT ID AS KV_UNTEREBENE_ID, KV_NUMMER AS KV_UNTEREBENE_NUMMER FROM tSK_KALV) AS tSK_KALV_UNTEREBENE ON tSK_KALV_UNTEREBENE.KV_UNTEREBENE_ID = tSK_KALP.KP_IDSKKV_POS) LEFT JOIN (SELECT ID AS KP_UNTEREBENE_IDSKKK, KK_TYP_HERKUNFT_BUCHUNG AS KP_UNTEREBENE_TYP_BUCHUNG, KK_TYP_LAGER_BUCHUNG AS KP_UNTEREBENE_TYP_LAGER_BUCHUNG FROM tSK_KALK ) AS tSK_KALK_UNTEREBENE ON tSK_KALK_UNTEREBENE.KP_UNTEREBENE_IDSKKK = tSK_KALP.KP_IDSKKK_POS) LEFT JOIN (SELECT ID AS KK_BEBP_ID, KK_IDBEBP AS KK_BEBP_IDBEBP, KK_IDBEBP_BASIS AS KK_BEBP_IDBEBP_BASIS FROM tSK_KALK) AS tSK_KALK_BEBP ON tSK_KALK_BEBP.KK_BEBP_ID = tSK_KALP.KP_IDSKKK) LEFT JOIN tBE_BELP ON tBE_BELP.ID = CASE WHEN tSK_KALK_BEBP.KK_BEBP_IDBEBP IS NOT NULL THEN tSK_KALK_BEBP.KK_BEBP_IDBEBP ELSE CASE WHEN tSK_KALK_BEBP.KK_BEBP_IDBEBP_BASIS IS NOT NULL THEN tSK_KALK_BEBP.KK_BEBP_IDBEBP_BASIS ELSE 0 END END) LEFT JOIN tBE_BELK ON tBE_BELK.ID = tBE_BELP.BP_IDBEBK) LEFT JOIN tBE_BELK_BKBE ON tBE_BELK_BKBE.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK) LEFT JOIN tBE_BELK_BKBU ON tBE_BELK_BKBU.BK_BKBU_IDBEBK = tBE_BELP.BP_IDBEBK) LEFT JOIN tNUKR ON tNUKR.ID = CASE WHEN tBE_BELK.BK_TYP = 0 THEN tBE_BELK_BKBU.BK_BKBU_IDNK ELSE CASE WHEN tBE_BELK.BK_TYP = 1 THEN tBE_BELK_BKBE.BK_BKBE_IDNK ELSE 0 END END) LEFT JOIN  (SELECT ID AS KP_EBENE_POS_IDSKKK, KK_TYP_LAGER_BUCHUNG AS KP_EBENE_POS_TYP_LAGER_BUCHUNG FROM  tSK_KALK  ) AS tSK_KALK_EBENE_POS  ON tSK_KALK_EBENE_POS.KP_EBENE_POS_IDSKKK = tSK_KALP.KP_IDSKKK)  WHERE tSK_KALP_LGBEWE.KPLG_IDSKKP = 126026 ORDER BY KPLG_DATUM ASC 
